function InputForm({TextPlaceholder, zstyle, type = "text",accept, Id, funct}) {
  return (
    <input
    type={type}
    className={"input "+ zstyle}
    placeholder={TextPlaceholder}
    accept={accept}
    id={Id}
    onChange={(e)=> funct?.(e)}
    />
  );
}

export default InputForm;
